namespace sv_f56a6664ab67415c83a91d4d6f906703.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_f56a6664ab67415c83a91d4d6f906703.Services

<div class="channel-list">
    <h3 class="channel-list-header">Channels</h3>
    @foreach (var channel in Channels)
    {
        <div class="channel-item @(channel.Id == SelectedChannelId ? "active" : "")"
             @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
            <div class="channel-name-row">
                <span class="channel-name"># @channel.Name</span>
                @if (channel.UnreadCount > 0)
                {
                    <span class="unread-badge">@channel.UnreadCount</span>
                }
            </div>
            <span class="channel-description">@TruncateDescription(channel.Description)</span>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string description)
    {
        return description.Length > 50 ? description[..47] + "..." : description;
    }
}

@using sv_f56a6664ab67415c83a91d4d6f906703.Services

<div class="message-area">
    <div class="message-area-header">
        <h2># @ChannelName</h2>
        <p>@ChannelDescription</p>
    </div>

    <div class="message-list" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages...</div>
        }

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ReplyCount="GetReplyCount(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")" ButtonLabel="Send" OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = string.Empty;
    [Parameter] public string ChannelDescription { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers load more (JS interop would be ideal for precise detection)
        await OnLoadMore.InvokeAsync();
    }
}

@using sv_f56a6664ab67415c83a91d4d6f906703.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="message-header">
                <span class="author">@RootMessage.Author</span>
                <span class="timestamp">@FormatRelativeTime(RootMessage.SentAt)</span>
            </div>
            <div class="message-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="author">@reply.Author</span>
                        <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread..." ButtonLabel="Reply" OnSubmit="OnReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.Now - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

