@using sv_f56a6664ab67415c83a91d4d6f906703.Services
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelList Channels="_channels"
                 SelectedChannelId="_selectedChannelId"
                 OnChannelSelected="SelectChannel" />

    <div class="main-content @(_threadOpen ? "thread-open" : "")">
        @if (_selectedChannel is not null)
        {
            <MessageArea ChannelName="@_selectedChannel.Name"
                         ChannelDescription="@_selectedChannel.Description"
                         Messages="_messages"
                         ThreadReplyCounts="_threadReplyCounts"
                         IsLoadingMore="_isLoadingMore"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage"
                         OnLoadMore="LoadMoreMessages" />
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<Message> _threadReplies = [];
    private Dictionary<int, int> _threadReplyCounts = [];
    private Channel? _selectedChannel;
    private int _selectedChannelId;
    private Message? _threadRootMessage;
    private bool _threadOpen;
    private bool _isLoadingMore;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channelId);
        await UpdateThreadReplyCounts();
        CloseThread();
        StateHasChanged();
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || _selectedChannel is null) return;
        _isLoadingMore = true;
        StateHasChanged();

        var olderMessages = await ChatService.GetMessagesAsync(_selectedChannelId, _messages.Count, PageSize);
        if (olderMessages.Count > 0)
        {
            _messages.InsertRange(0, olderMessages);
            await UpdateThreadReplyCounts();
        }

        _isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;
        var message = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
        _messages.Add(message);
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(messageId);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _selectedChannel is null) return;
        var reply = await ChatService.SendMessageAsync(_selectedChannelId, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update reply count
        _threadReplyCounts[_threadRootMessage.Id] = _threadReplies.Count;
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
        // Refresh messages to show updated reactions
        if (_selectedChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_selectedChannelId, 0, _messages.Count);
        }
    }

    private async Task UpdateThreadReplyCounts()
    {
        _threadReplyCounts = [];
        // Identify thread starters (messages that have replies pointing to them)
        var rootIds = _messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToList();

        foreach (var rootId in rootIds)
        {
            var thread = await ChatService.GetThreadAsync(rootId);
            if (thread.Count > 0)
            {
                _threadReplyCounts[rootId] = thread.Count;
            }
        }
    }
}
